# gene_venn.py

import matplotlib.pyplot as plt
from matplotlib_venn import venn2
import os

def plot_gene_venn(list1, list2, label1="List1", label2="List2", output_file="gene_venn.png"):
    """
    绘制两个基因列表的韦恩图，并返回交集基因。
    
    参数:
        list1, list2: 基因名称列表（字符串），可包含大小写
        label1, label2: 韦恩图中两个集合的标签
        output_file: 输出图像文件名（支持 .png, .pdf 等）
    
    返回:
        intersection: 交集基因集合（大写）
    """
    # 转换为大写并去重
    set1 = set(gene.strip().upper() for gene in list1 if gene.strip())
    set2 = set(gene.strip().upper() for gene in list2 if gene.strip())

    # 计算交集
    intersection = set1 & set2
    only_in_1 = set1 - set2
    only_in_2 = set2 - set1
    
    print_statistics(set1, set2, intersection, only_in_1, only_in_2, label1, label2)
    
    # 绘制韦恩图
    plt.figure(figsize=(8, 6))
    venn2(
        subsets=(len(only_in_1), len(only_in_2), len(intersection)),
        set_labels=(label1, label2),
        set_colors=('skyblue', 'lightcoral'),
        alpha=0.7
    )
    plt.title("Gene Venn Diagram", fontsize=14)
    plt.tight_layout()
    
    # 保存图像
    plt.savefig(output_file, dpi=300, bbox_inches='tight')
    print(f"\n✅ 韦恩图已保存至: {os.path.abspath(output_file)}")
    plt.close()

    return intersection

def export_genes_to_file(genes, filename="intersection_genes.txt"):
    """
    导出基因列表到文件。
    
    参数:
        genes: 基因名称列表或集合
        filename: 输出文件名
    """
    with open(filename, "w") as f:
        for gene in sorted(genes):
            f.write(f"{gene}\n")
    print(f"📚 交集基因已导出至: {os.path.abspath(filename)}")

def print_statistics(set1, set2, intersection, only_in_1, only_in_2, label1, label2):
    """打印统计信息"""
    print(f"【{label1}】基因数: {len(set1)}")
    print(f"【{label2}】基因数: {len(set2)}")
    print(f"交集基因数: {len(intersection)}")
    print(f"仅在 {label1}: {len(only_in_1)}")
    print(f"仅在 {label2}: {len(only_in_2)}")
    
    if intersection:
        print("\n交集基因:")
        for gene in sorted(intersection):
            print(f"  - {gene}")
    else:
        print("\n⚠️ 无交集基因！")

